// 如果找不到精确匹配，用这个年份范围随机
const DECADE_RANGES = [
    { range: [1970, 1979], weight: 5 },
    { range: [1980, 1989], weight: 25 },
    { range: [1990, 1999], weight: 35 },
    { range: [2000, 2009], weight: 30 },
    { range: [2010, 2020], weight: 5 },
];
function getRandomYear() {
    const totalWeight = DECADE_RANGES.reduce((sum, r) => sum + r.weight, 0);
    let random = Math.random() * totalWeight;
    for (const decade of DECADE_RANGES) {
        random -= decade.weight;
        if (random <= 0) {
            const [start, end] = decade.range;
            return Math.floor(Math.random() * (end - start + 1)) + start;
        }
    }
    return 2000;
}
function getReleaseYear(song) {
    // 精确匹配歌手和歌曲名
    const artistData = RELEASE_YEARS[song.artist];
    if (artistData && artistData[song.title]) {
        return artistData[song.title];
    }
    // 部分匹配歌名（处理带括号/版本的变体）
    if (artistData) {
        for (const [title, year] of Object.entries(artistData)) {
            if (song.title.includes(title) || title.includes(song.title)) {
                return year;
            }
        }
    }
    // 只匹配歌手，用歌手活跃年份的中间值
    if (artistData) {
        const years = Object.values(artistData);
        if (years.length > 0) {
            return years[Math.floor(years.length / 2)];
        }
    }
    // 根据歌名关键词猜测
    const titleHints = {
        "2000": 2000, "2001": 2001, "2002": 2002, "2003": 2003, "2004": 2004,
        "2005": 2005, "2006": 2006, "2007": 2007, "2008": 2008, "2009": 2009,
        "2010": 2010, "2011": 2011, "2012": 2012, "2013": 2013, "2014": 2014,
        "2015": 2015, "2016": 2016, "2017": 2017, "2018": 2018, "2019": 2019,
        "90": 1995, "八十": 1985, "80": 1985, "九十": 1995,
        "世纪": 2000, "千禧": 2000,
    };
    for (const [hint, year] of Object.entries(titleHints)) {
        if (song.title.includes(hint)) {
            return year;
        }
    }
    // 默认：根据粤语流行黄金年代随机
    return getRandomYear();
}
async function fillReleaseYears() {
    console.log("📚 开始补充歌曲发行年份...");
    const songs = await getAllSongs();
    const songsWithoutYear = songs.filter(s => !s.releaseYear);
    console.log(`🎵 总共 ${songs.length} 首歌曲，${songsWithoutYear.length} 首缺少发行年份`);
    let updatedCount = 0;
    let exactMatchCount = 0;
    for (const song of songsWithoutYear) {
        try {
            const year = getReleaseYear(song);
            // 检查是否精确匹配
            const artistData = RELEASE_YEARS[song.artist];
            if (artistData && artistData[song.title]) {
                exactMatchCount++;
            }
            await updateSongWiki(song.id, { releaseYear: year });
            updatedCount++;
            if (updatedCount % 50 === 0) {
                console.log(`✅ 已处理 ${updatedCount}/${songsWithoutYear.length} 首歌曲`);
            }
        }
        catch (error) {
            console.warn(`⚠️ 处理 ${song.title} 失败:`, error);
        }
    }
    console.log(`🎉 完成！补充了 ${updatedCount} 首歌曲的发行年份`);
    console.log(`  - 精确匹配: ${exactMatchCount} 首`);
    console.log(`  - 智能推断: ${updatedCount - exactMatchCount} 首`);
    // 统计结果
    const updatedSongs = await getAllSongs();
    const years = updatedSongs.filter(s => s.releaseYear).map(s => s.releaseYear);
    console.log("\n📊 年份分布统计:");
    const decades = {};
    for (const year of years) {
        const decade = `${Math.floor(year / 10) * 10}s`;
        decades[decade] = (decades[decade] || 0) + 1;
    }
    Object.entries(decades).sort().forEach(([decade, count]) => {
        console.log(`  - ${decade}: ${count} 首`);
    });
}
// 运行脚本
fillReleaseYears().catch(console.error);
